// Pre-filter items before sending to AI to control cost.
// Drops items that carry too little content to classify and caps the batch
// at AI_MAX_ITEMS_PER_BATCH (default 30, from config/openai-cost-controls.json).
const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];

const MAX_ITEMS = Number($vars.AI_MAX_ITEMS_PER_BATCH) > 0
  ? Number($vars.AI_MAX_ITEMS_PER_BATCH)
  : 30;
const MIN_CONTENT_LENGTH = 10;

// Drop items that have neither a usable headline nor a body.
const filtered = items.filter(item => {
  const headlineLen = (typeof item.headline === 'string') ? item.headline.trim().length : 0;
  const bodyLen = (typeof item.body === 'string') ? item.body.trim().length : 0;
  return (headlineLen + bodyLen) >= MIN_CONTENT_LENGTH;
});

// Cap at the maximum batch size, keeping the first MAX_ITEMS entries.
// Items arrive in descending priority order from upstream clustering.
const capped = filtered.slice(0, MAX_ITEMS);

return [{
  json: {
    ...input,
    items: capped,
    _prefilter_in: items.length,
    _prefilter_out: capped.length
  }
}];

// Expand the pre-filtered items array into individual items for per-item AI classification.
const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];
return items.map(item => ({ json: item }));

