// Parse and validate the AI JSON output against the alert_classification schema.
// Falls back gracefully when the AI returns malformed output.
const item = $input.item.json;
const rawContent = item?.message?.content || item?.choices?.[0]?.message?.content || '';

const VALID_TOPICS = ['crypto', 'finance', 'economy', 'health', 'ai', 'energy', 'technology'];
const VALID_SOURCE_TYPES = ['rss', 'api', 'social', 'webhook', 'x_account', 'x_query'];
const VALID_SOURCE_ROLES = ['confirmation', 'data', 'commentary', 'official'];

let ai;
try {
  // Strip potential markdown code fences
  const cleaned = rawContent.replace(/^```[a-zA-Z]*\r?\n?|\r?\n?```$/g, '').trim();
  ai = JSON.parse(cleaned);
} catch (e) {
  // Parsing failed — return a low-confidence fallback
  ai = {
    topic_slug: $('Expand Items').item.json.topic_candidates?.[0] || 'technology',
    secondary_topics: [],
    headline: $('Expand Items').item.json.headline,
    summary_text: $('Expand Items').item.json.body?.slice(0, 500) || $('Expand Items').item.json.headline,
    severity_score: 0,
    importance_score: 0,
    confidence_score: 0,
    send_alert: false,
    alert_reason: 'AI output parse failure — skipping alert.',
    cluster_label: null,
    source_confidence_note: null,
    supporting_sources: null
  };
}

// Validate required fields
if (!VALID_TOPICS.includes(ai.topic_slug)) {
  ai.topic_slug = $('Expand Items').item.json.topic_candidates?.[0] || 'technology';
}
if (typeof ai.severity_score  !== 'number') ai.severity_score  = 0;
if (typeof ai.importance_score !== 'number') ai.importance_score = 0;
if (typeof ai.confidence_score !== 'number') ai.confidence_score = 0;
if (typeof ai.send_alert !== 'boolean') ai.send_alert = false;

const source = $('Expand Items').item.json;
const sourceConfidenceNote = ai.source_confidence_note == null
  ? null
  : String(ai.source_confidence_note).slice(0, 300) || null;

// Normalise source_url: trim whitespace; reject non-HTTP/HTTPS values.
const sourceUrl = typeof source.source_url === 'string' && source.source_url.trim() !== ''
  ? source.source_url.trim()
  : null;

// Extract source_domain from source_url
let sourceDomain = null;
if (sourceUrl) {
  try {
    const u = new URL(sourceUrl);
    if (u.protocol === 'http:' || u.protocol === 'https:') {
      sourceDomain = u.hostname || null;
    }
  } catch (_) {
    sourceDomain = null;
  }
}

// Validate and normalise supporting_sources from the AI output.
// Iterate the full array and collect up to 5 valid entries; invalid entries are
// silently dropped so that a bad early entry does not discard a valid later one.
// Only HTTP/HTTPS source URLs are accepted.
let supportingSources = null;
if (Array.isArray(ai.supporting_sources) && ai.supporting_sources.length > 0) {
  const validated = [];
  for (const ss of ai.supporting_sources) {
    if (validated.length >= 5) break;
    if (!ss || typeof ss !== 'object') continue;
    if (typeof ss.source_name !== 'string' || ss.source_name.trim() === '') continue;
    let ssUrl = null;
    if (typeof ss.source_url === 'string' && ss.source_url.trim() !== '') {
      const trimmedSsUrl = ss.source_url.trim();
      try {
        const u = new URL(trimmedSsUrl);
        if (u.protocol === 'http:' || u.protocol === 'https:') {
          ssUrl = trimmedSsUrl;
        }
      } catch (_) {
        ssUrl = null;
      }
    }
    validated.push({
      source_name: ss.source_name.trim(),
      source_url:  ssUrl,
      source_type: VALID_SOURCE_TYPES.includes(ss.source_type) ? ss.source_type : null,
      source_role: VALID_SOURCE_ROLES.includes(ss.source_role) ? ss.source_role : null
    });
  }
  supportingSources = validated.length > 0 ? validated : null;
}

return [{
  json: {
    item_id:            source.item_id,
    topic_slug:         ai.topic_slug,
    secondary_topics:   Array.isArray(ai.secondary_topics) ? ai.secondary_topics.filter(t => VALID_TOPICS.includes(t)).slice(0, 2) : [],
    headline:           (ai.headline || source.headline || '').slice(0, 250),
    summary_text:       (ai.summary_text || source.body || source.headline || '').slice(0, 500),
    source_url:         sourceUrl,
    source_name:        source.source_name,
    source_type:        source.source_type || null,
    source_domain:      sourceDomain,
    supporting_sources: supportingSources,
    trust_tier:         source.trust_tier || null,
    trust_score:        typeof source.trust_score === 'number' ? source.trust_score : null,
    severity_score:     Math.min(100, Math.max(0, Math.round(ai.severity_score))),
    importance_score:   Math.min(100, Math.max(0, Math.round(ai.importance_score))),
    confidence_score:   Math.min(100, Math.max(0, Math.round(ai.confidence_score))),
    send_alert:         ai.send_alert === true,
    alert_reason:       ai.alert_reason || null,
    event_at:           source.published_at,
    cluster_label:      ai.cluster_label || source.cluster_label || null,
    source_confidence_note: sourceConfidenceNote
  }
}];

// Collect all classified alerts and return them as the workflow output.
const items = $input.all().map(i => i.json);
return [{ json: { items } }];
